def main():
    n = int(input())
    s = input()
    x = list(map(int, input().split()))
    if s.count('L') == 0 or s.count('R') == 0:
        print(-1)
        return
    for i in range(n):
        if s[i] == 'L' and x[i] == x[i + 1]:
            print(i + 1)
            return
    print(-1)


if __name__ == '__main__':
    main()
